import { products } from "../data.js";
import type { Product } from "../types.js";

export interface ProductFilters {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

export interface ProductSummary {
  count: number;
  totalInventoryValue: number;
  averagePrice: number;
}

export interface ProductWithDetails extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

export interface ProductListResult {
  products: Product[];
  summary: ProductSummary;
}

export type ServiceResult<T> =
  | { success: true; data: T }
  | { success: false; error: string };

function enrichProduct(product: Product): ProductWithDetails {
  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}

export function getProducts(filters: ProductFilters): ProductListResult {
  let filtered = [...products];

  if (filters.category !== undefined) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }

  if (filters.minPrice !== undefined) {
    const min = filters.minPrice;
    filtered = filtered.filter((p) => p.price >= min);
  }

  if (filters.maxPrice !== undefined) {
    const max = filters.maxPrice;
    filtered = filtered.filter((p) => p.price <= max);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

export function getProductById(id: number): ServiceResult<ProductWithDetails> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return { success: false, error: "Product not found" };
  }

  return { success: true, data: enrichProduct(product) };
}

export function adjustStock(
  id: number,
  adjustment: number
): ServiceResult<ProductWithDetails> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return { success: false, error: "Product not found" };
  }

  if (typeof adjustment !== "number") {
    return { success: false, error: "adjustment must be a number" };
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    return { success: false, error: "Insufficient stock" };
  }

  product.stock = newStock;

  return { success: true, data: enrichProduct(product) };
}

